/**
 * A single remote-operation permission entry.
 *
 * V0.2: replaces `RemotePermissionRequest`. The [`super::Permissions::remote_permission`] method
 * now accepts a `Vec<RemotePermission>` so products can batch multiple
 * permission requests into a single prompt.
 *
 * See [RFC 0001] and [issue #64].
 *
 * [RFC 0001]: https://github.com/paritytech/triangle-js-sdks/pull/66
 * [issue #64]: https://github.com/paritytech/triangle-js-sdks/issues/64
 */
export type RemotePermission =
  /**
   * HTTP/HTTPS/WS/WSS access to specific domains. Each string is a domain
   * pattern: `"api.example.com"` (exact), `"*.example.com"` (wildcard
   * subdomain), or `"*"` (all hosts).
   */
  | { tag: "Remote"; value: Array<string> }
  /** WebRTC access — can expose the user's IP address. */
  | { tag: "WebRtc"; value: undefined }
  /**
   * Broadcast signed transactions via
   * [`super::ChainInteraction::remote_chain_transaction_broadcast`].
   */
  | { tag: "ChainSubmit"; value: undefined }
  /** Submit statements via [`super::StatementStore::remote_statement_store_submit`]. */
  | { tag: "StatementSubmit"; value: undefined }
;

export const RemotePermission: S.Codec<RemotePermission> = S.lazy((): S.Codec<RemotePermission> => S.taggedUnion({Remote: S.vec(S.str), WebRtc: S.unit, ChainSubmit: S.unit, StatementSubmit: S.unit}));

/**
 * Request wrapper for `remote_permission`.
 *
 * V1 mirrors `host-api@0.6.x`'s single-permission `ExternalRequest(String) |
 * TransactionSubmit`; V2 batches multiple [`RemotePermission`] entries per
 * RFC-0001.
 */
export type RemotePermissionRequest =
  /** Pre-RFC-0001 single-permission request. */
  | { tag: "V1"; value: RemotePermissionRequestV1 }
  /** RFC-0001 batch request. */
  | { tag: "V2"; value: Array<RemotePermission> }
;

export const RemotePermissionRequest: S.Codec<RemotePermissionRequest> = S.lazy((): S.Codec<RemotePermissionRequest> => S.taggedUnion({V1: RemotePermissionRequestV1, V2: S.vec(RemotePermission)}));

/**
 * Pre-RFC-0001 remote operation permission, as shipped by
 * `@novasamatech/host-api@0.6.x`. Suffixed with `V1` so the simple name
 * doesn't collide with the versioned wrapper `RemotePermissionRequest`
 * when both reach the codegen output (rustdoc flattens module paths).
 */
export type RemotePermissionRequestV1 =
  /** URL the product wants to fetch. */
  | { tag: "ExternalRequest"; value: string }
  /** Product wants to submit a transaction. */
  | { tag: "TransactionSubmit"; value: undefined }
;

export const RemotePermissionRequestV1: S.Codec<RemotePermissionRequestV1> = S.lazy((): S.Codec<RemotePermissionRequestV1> => S.taggedUnion({ExternalRequest: S.str, TransactionSubmit: S.unit}));

/** Response wrapper for `remote_permission`. */
export type RemotePermissionResponse =
  | { tag: "V1"; value: boolean }
  | { tag: "V2"; value: boolean }
;

export const RemotePermissionResponse: S.Codec<RemotePermissionResponse> = S.lazy((): S.Codec<RemotePermissionResponse> => S.taggedUnion({V1: S.bool, V2: S.bool}));

